import argparse  # Library to parse the arguments when running the server script.
import socket     # Importing the socket module
from datetime import datetime   # Importing the datetime module


def main():
    parser = argparse.ArgumentParser(description='TCP and UDP client for testing game servers')

    parser.add_argument('--port', type=int, default=12345)
    parser.add_argument('host', help='The host to connect to.')
    parser.add_argument('-s', '--status-server', action="store_true")
    args = parser.parse_args()

    print(f"Connecting {args}")


    with socket.socket(family=socket.AF_INET, type=socket.SOCK_DGRAM) as client:

        # Bind to localhost and given port
        client.bind(('localhost', args.port))

        while True:
            msg = input()

            if not msg == 'exit':
                try:
                    # Send the message to the server on the given host and port
                    client.sendto(msg, (args.host, 23456))

                    # Wait for the response from the server with a timeout of 1 second or until it times out
                    resp = client.recvfrom(1024)[0]
                    print("Client Received: " + str(resp))
                except KeyboardInterrupt as ki:
                    exit()
            else:
                break